import React from 'react';

interface MetricCard {
    label: string;
    value: string;
    hint: string;
}

const metrics: MetricCard[] = [
    { label: 'Clientes ativos', value: '1.248', hint: '+12 no mês' },
    { label: 'OS em aberto', value: '37', hint: '11 críticas' },
    { label: 'Boletos pendentes', value: 'R$ 84.320', hint: 'venc. em 7 dias' },
    { label: 'Uptime da rede', value: '99,83%', hint: 'últimos 30 dias' },
];

const pendingActions: string[] = [
    'Aprovar 4 novos logins de técnicos',
    'Revisar 8 clientes com atraso > 30 dias',
    'Validar migração de base antiga (lote #03)',
];

const Dashboard: React.FC = () => {
    return (
        <div style={{ padding: '1rem 1.25rem' }}>
            <h1 style={{ marginBottom: '0.25rem' }}>Dashboard</h1>
            <p style={{ marginTop: 0, color: '#475569' }}>
                Visão operacional rápida do provedor para tomada de decisão diária.
            </p>

            <section
                style={{
                    display: 'grid',
                    gridTemplateColumns: 'repeat(auto-fit, minmax(220px, 1fr))',
                    gap: '0.85rem',
                    marginTop: '1rem',
                }}
            >
                {metrics.map((metric) => (
                    <article
                        key={metric.label}
                        style={{ background: '#fff', border: '1px solid #e2e8f0', borderRadius: 10, padding: '1rem' }}
                    >
                        <small style={{ color: '#64748b' }}>{metric.label}</small>
                        <h2 style={{ margin: '0.4rem 0 0.2rem', fontSize: '1.4rem' }}>{metric.value}</h2>
                        <small style={{ color: '#0f766e' }}>{metric.hint}</small>
                    </article>
                ))}
            </section>

            <section
                style={{
                    marginTop: '1rem',
                    background: '#fff',
                    border: '1px solid #e2e8f0',
                    borderRadius: 10,
                    padding: '1rem',
                }}
            >
                <h3 style={{ marginTop: 0 }}>Pendências prioritárias</h3>
                <ul style={{ marginBottom: 0 }}>
                    {pendingActions.map((action) => (
                        <li key={action} style={{ marginBottom: '0.5rem' }}>
                            {action}
                        </li>
                    ))}
                </ul>
            </section>
        </div>
    );
};

export default Dashboard;
